   175→// Login
   176→async function handleLogin(event) {
   177→  event.preventDefault();
   178→  const form = event.target;
   179→  const submitBtn = form.querySelector('button[type="submit"]');
   180→  const errorEl = document.getElementById('login-error');
   181→
   182→  submitBtn.disabled = true;
   183→  submitBtn.textContent = 'Signing in...';
   184→  if (errorEl) errorEl.style.display = 'none';
   185→
   186→  try {
   187→    const response = await fetch('/api/auth/login', {
   188→      method: 'POST',
   189→      headers: { 'Content-Type': 'application/json' },
   190→      body: JSON.stringify({
   191→        email: form.email.value,
   192→        password: form.password.value
   193→      })
   194→    });
   195→
   196→    const data = await response.json();
   197→
   198→    if (data.success) {
   199→      localStorage.setItem(TOKEN_KEY, data.accessToken || data.token);
   200→      if (data.refreshToken) {
   201→        localStorage.setItem(REFRESH_KEY, data.refreshToken);
   202→      }
   203→      // Redirect based on role - all recruiter-type roles go to recruiter dashboard
   204→      const recruiterRoles = ['recruiter', 'hiring_manager', 'employer', 'admin'];
   205→      window.location.href = recruiterRoles.includes(data.user?.role)
   206→        ? '/recruiter-dashboard.html'
   207→        : '/candidate-dashboard.html';
   208→    } else {
   209→      if (errorEl) {
   210→        errorEl.textContent = data.error || 'Login failed';
   211→        errorEl.style.display = 'block';
   212→      }
   213→    }
   214→  } catch (err) {
   215→    if (errorEl) {
   216→      errorEl.textContent = 'Network error. Please try again.';
   217→      errorEl.style.display = 'block';
   218→    }
   219→  } finally {
   220→    submitBtn.disabled = false;
   221→    submitBtn.textContent = 'Sign In';
   222→  }
   223→}
