   225→// Logout
   226→async function handleLogout() {
   227→  const token = localStorage.getItem(TOKEN_KEY);
   228→  if (token) {
   229→    try {
   230→      await fetch('/api/auth/logout', {
   231→        method: 'POST',
   232→        headers: { 'Authorization': `Bearer ${token}` }
   233→      });
   234→    } catch (e) {
   235→      // Ignore errors during logout
   236→    }
   237→  }
   238→  localStorage.removeItem(TOKEN_KEY);
   239→  localStorage.removeItem(REFRESH_KEY);
   240→  window.location.href = '/';
   241→}
