   277→// Dashboard functions
   278→async function loadDashboard() {
   279→  const user = await checkAuth();
   280→  if (!user) {
   281→    window.location.href = '/login.html';
   282→    return;
   283→  }
   284→
   285→  // Update user info
   286→  const userNameEl = document.getElementById('user-name');
   287→  if (userNameEl) {
   288→    userNameEl.textContent = user.name || user.email.split('@')[0];
   289→  }
   290→
   291→  // Load stats
   292→  loadInterviewStats();
   293→  loadRecentInterviews();
