   296→async function loadInterviewStats() {
   297→  try {
   298→    const data = await apiCall('/interviews/stats/summary');
   299→    if (!data) return;
   300→
   301→    const { stats, recent_scores } = data;
   302→
   303→    // Update stat cards
   304→    const totalEl = document.getElementById('total-interviews');
   305→    const avgEl = document.getElementById('avg-score');
   306→    const bestEl = document.getElementById('best-score');
   307→
   308→    if (totalEl) totalEl.textContent = stats?.completed || 0;
   309→    if (avgEl) avgEl.textContent = stats?.avg_score ? parseFloat(stats.avg_score).toFixed(1) : '-';
   310→    if (bestEl) bestEl.textContent = stats?.best_score || '-';
   311→
   312→  } catch (err) {
   313→    console.error('Failed to load stats:', err);
