   317→async function loadRecentInterviews() {
   318→  try {
   319→    const data = await apiCall('/interviews/history?limit=5');
   320→    if (!data) return;
   321→
   322→    const listEl = document.getElementById('recent-interviews');
   323→    if (!listEl) return;
   324→
   325→    if (!data.interviews || data.interviews.length === 0) {
   326→      listEl.innerHTML = `
   327→        <div class="empty-state">
   328→          <p>No interviews yet. Start practicing!</p>
   329→          <a href="/interview.html" class="btn btn-primary">Start Mock Interview</a>
   330→        </div>
   331→      `;
   332→      return;
   333→    }
   334→
   335→    listEl.innerHTML = data.interviews.map(interview => `
   336→      <div class="interview-item">
   337→        <div class="interview-info">
   338→          <span class="interview-type">${interview.interview_type}</span>
   339→          <span class="interview-date">${new Date(interview.created_at).toLocaleDateString()}</span>
   340→        </div>
   341→        <div class="interview-score">
   342→          ${interview.overall_score ? `<span class="score">${interview.overall_score}/10</span>` : '<span class="pending">In Progress</span>'}
   343→        </div>
   344→        <a href="/interview.html?id=${interview.id}" class="btn btn-ghost btn-sm">
   345→          ${interview.status === 'completed' ? 'Review' : 'Continue'}
   346→        </a>
   347→      </div>
   348→    `).join('');
   349→
   350→  } catch (err) {
   351→    console.error('Failed to load interviews:', err);
   352→  }
   353→}
