   407→// Dashboard Mobile Sidebar Toggle
   408→function initDashboardSidebar() {
   409→  const sidebar = document.querySelector('.sidebar');
   410→  if (!sidebar) return; // Not on a dashboard page
   411→
   412→  // Create mobile toggle button
   413→  let mobileToggle = document.querySelector('.mobile-sidebar-toggle');
   414→  if (!mobileToggle) {
   415→    mobileToggle = document.createElement('button');
   416→    mobileToggle.className = 'mobile-sidebar-toggle';
   417→    mobileToggle.innerHTML = '☰';
   418→    mobileToggle.setAttribute('aria-label', 'Toggle sidebar');
   419→    document.body.appendChild(mobileToggle);
   420→  }
   421→
   422→  // Create overlay
   423→  let overlay = document.querySelector('.sidebar-overlay');
   424→  if (!overlay) {
   425→    overlay = document.createElement('div');
   426→    overlay.className = 'sidebar-overlay';
   427→    document.body.appendChild(overlay);
   428→  }
   429→
   430→  // Toggle sidebar
   431→  mobileToggle.addEventListener('click', () => {
   432→    sidebar.classList.toggle('mobile-open');
   433→    overlay.classList.toggle('active');
   434→    mobileToggle.innerHTML = sidebar.classList.contains('mobile-open') ? '✕' : '☰';
   435→  });
   436→
   437→  // Close sidebar when clicking overlay
   438→  overlay.addEventListener('click', () => {
   439→    sidebar.classList.remove('mobile-open');
   440→    overlay.classList.remove('active');
   441→    mobileToggle.innerHTML = '☰';
   442→  });
   443→
   444→  // Close sidebar when clicking nav items on mobile
   445→  const navItems = sidebar.querySelectorAll('.nav-item');
   446→  navItems.forEach(item => {
   447→    item.addEventListener('click', () => {
   448→      if (window.innerWidth <= 768) {
   449→        sidebar.classList.remove('mobile-open');
   450→        overlay.classList.remove('active');
   451→        mobileToggle.innerHTML = '☰';
   452→      }
   453→    });
   454→  });
   455→}
   456→
   457→// Initialize on page load
   458→document.addEventListener('DOMContentLoaded', () => {
   459→  // Handle OAuth callback tokens first
   460→  handleOAuthCallback();
   461→
   462→  // Initialize mobile menu
   463→  initMobileMenu();
   464→
   465→  // Initialize dashboard sidebar
   466→  initDashboardSidebar();
   467→
   468→  // Check if on dashboard
   469→  if (window.location.pathname === '/dashboard.html' ||
   470→      window.location.pathname === '/candidate-dashboard.html') {
   471→    loadDashboard();
   472→  } else if (window.location.pathname === '/recruiter-dashboard.html') {
   473→    checkAuth().then(user => {
   474→      if (!user) {
   475→        window.location.href = '/login.html';
   476→      }
   477→    });
   478→  } else {
   479→    checkAuth();
   480→  }
   481→
   482→  // Attach form handlers
   483→  const registerForm = document.getElementById('register-form');
   484→  if (registerForm) {
   485→    registerForm.addEventListener('submit', handleRegister);
   486→  }
   487→
   488→  const loginForm = document.getElementById('login-form');
   489→  if (loginForm) {
   490→    loginForm.addEventListener('submit', handleLogin);
   491→  }
   492→
   493→  // Attach logout handlers
   494→  document.querySelectorAll('[data-logout]').forEach(el => {
   495→    el.addEventListener('click', (e) => {
   496→      e.preventDefault();
   497→      handleLogout();
   498→    });
   499→  });
   500→});
   501→
   502→// Expose functions globally for inline use
   503→window.handleLogout = handleLogout;
   504→window.apiCall = apiCall;
   505→window.currentUser = () => currentUser;
