    97→// API call helper
    98→async function authApiCall(endpoint, options = {}) {
    99→  const token = getAuthToken();
   100→  const url = endpoint.startsWith('/api') ? endpoint : `/api${endpoint}`;
   101→  const headers = {
   102→    'Authorization': `Bearer ${token}`,
   103→    'Content-Type': 'application/json',
   104→    ...options.headers
   105→  };
   106→  const response = await fetch(url, { ...options, headers });
   107→  if (!response.ok) throw new Error(`API error: ${response.status}`);
   108→  return response.json();
   109→}
