   111→function setupUserMenu() {
   112→  const token = getAuthToken();
   113→  if (!token) {
   114→    window.location.href = '/login.html';
   115→    return;
   116→  }
   117→
   118→  // Load user info
   119→  fetch('/api/auth/me', { headers: { 'Authorization': `Bearer ${token}` } })
   120→    .then(res => {
   121→      if (!res.ok) {
   122→        if (res.status === 401) window.location.href = '/login.html';
   123→        throw new Error('Auth failed');
   124→      }
   125→      return res.json();
   126→    })
   127→    .then(data => {
   128→      const user = data.user || data;
   129→      const nameEl = document.getElementById('user-name');
   130→      const avatarEl = document.getElementById('user-avatar');
