   393→  if (diffMins < 1) return 'Just now';
   394→  if (diffMins < 60) return `${diffMins}m ago`;
   395→  if (diffHours < 24) return `${diffHours}h ago`;
   396→  if (diffDays < 7) return `${diffDays}d ago`;
   397→
