    95→    const recruiterSignups = signupFunnelResult.rows.find(r => r.event_type === 'signup_complete_recruiter')?.sessions || 0;
    96→    const totalSignups = candidateSignups + recruiterSignups;
    97→
    98→    res.json({
    99→      success: true,
   100→      data: {
